from collections import Counter
import unicodedata

app = Flask(__name__)

class SpamDetector:
    def __init__(self):
        self.model = None
        self.vectorizer = None
        self.pipeline = None
        self.train_data_hash = None
        
    def preprocess_text(self, text):
        if not isinstance(text, str):
            text = str(text)
        
        text = unicodedata.normalize('NFKD', text)
        text = text.lower()
        text = re.sub(r'http[s]?://(?:[a-zA-Z]|[0-9]|[$-_@.&+]|[!*\\(\\),]|(?:%[0-9a-fA-F][0-9a-fA-F]))+', ' URL ', text)
        text = re.sub(r'\S+@\S+', ' EMAIL ', text)
        text = re.sub(r'\d+', ' NUM ', text)
        text = re.sub(r'(.)\1{2,}', r'\1\1', text)
        text = re.sub(r'[^\w\s]', ' ', text)
        text = re.sub(r'\s+', ' ', text)
        text = text.strip()
        
        return text
    
    def detect_evasion_attempts(self, text):
        evasion_indicators = []
        
        if len(text) > 50000:
            evasion_indicators.append('excessive_length')
        
        char_freq = Counter(text)
        total_chars = len(text)
        if total_chars > 0:
            special_char_ratio = sum(1 for c in text if not c.isalnum() and not c.isspace()) / total_chars
            if special_char_ratio > 0.5:
                evasion_indicators.append('excessive_special_chars')
        
        whitespace_ratio = sum(1 for c in text if c.isspace()) / max(total_chars, 1)
        if whitespace_ratio > 0.7:
            evasion_indicators.append('excessive_whitespace')
        
        words = text.split()
        if len(words) > 0:
            avg_word_length = sum(len(w) for w in words) / len(words)
            if avg_word_length > 20:
                evasion_indicators.append('abnormal_word_length')
        
        unicode_chars = sum(1 for c in text if ord(c) > 127)
        if total_chars > 0 and unicode_chars / total_chars > 0.3:
            evasion_indicators.append('excessive_unicode')
        
        repeated_patterns = re.findall(r'(.{3,})\1{3,}', text)
        if len(repeated_patterns) > 5:
            evasion_indicators.append('repeated_patterns')
        
        return evasion_indicators
    
    def train(self, X_train, y_train):
        X_train_processed = [self.preprocess_text(text) for text in X_train]
        
        self.vectorizer = TfidfVectorizer(
            max_features=5000,
            min_df=2,
            max_df=0.95,
            ngram_range=(1, 2),
            strip_accents='unicode',
            lowercase=True,
            token_pattern=r'\b\w+\b'
        )
        
        self.model = LogisticRegression(
            C=1.0,
            max_iter=1000,
            random_state=42,
            class_weight='balanced'
        )
        
        self.pipeline = Pipeline([
            ('vectorizer', self.vectorizer),
            ('classifier', self.model)
        ])
        
        self.pipeline.fit(X_train_processed, y_train)
        
        train_str = ''.join(X_train_processed) + ''.join(map(str, y_train))
        self.train_data_hash = hashlib.sha256(train_str.encode()).hexdigest()
        
    def predict_proba(self, text):
        if self.pipeline is None:
            raise ValueError("Model not trained yet")
        
        evasion_attempts = self.detect_evasion_attempts(text)
        
        processed_text = self.preprocess_text(text)
        
        if len(processed_text.strip()) == 0:
            return {
                'spam_probability': 0.5,
                'is_spam': False,
                'evasion_detected': True,
                'evasion_indicators': ['empty_text'] + evasion_attempts,
                'confidence': 'low'
            }
        
        proba = self.pipeline.predict_proba([processed_text])[0]
        spam_prob = float(proba[1])
        
        if evasion_attempts:
            spam_prob = min(spam_prob + 0.3, 1.0)
        
        is_spam = spam_prob > 0.5
        
        if spam_prob > 0.8 or spam_prob < 0.2:
            confidence = 'high'
        elif spam_prob > 0.65 or spam_prob < 0.35:
            confidence = 'medium'
        else:
            confidence = 'low'
        
        return {
            'spam_probability': spam_prob,
            'is_spam': is_spam,
            'evasion_detected': len(evasion_attempts) > 0,
            'evasion_indicators': evasion_attempts,
            'confidence': confidence
        }

